import buildDebug from 'debug'
import { sql } from 'drizzle-orm'

import { errorUtils, pluginUtils, searchUtils } from '@verdaccio/core'
import { Config, Logger, Token, TokenFilter } from '@verdaccio/types'
import {
  getDatabase,
  type Database,
  ENV,
  EventLogService,
  type Method,
  type Downloads,
  type DownloadsByVersion,
  DownloadsService,
  GlobalTadirService,
  LocalPackagesService,
  PackageService,
  TokenService,
  VerdaccioSecretService,
} from '@verdaccio-pro/database'

import SqlStorageHandler from './storage-handler'

export interface StorageConfig {
  url?: string
}

const debug = buildDebug('verdaccio:plugin:pro:storage:sql')

class SqlStoragePlugin
  extends pluginUtils.Plugin<StorageConfig>
  implements pluginUtils.Storage<StorageConfig> {
  public logger: Logger
  public config: Config
  private storageConfig: StorageConfig
  private db: Database
  private token: TokenService
  private localPackage: LocalPackagesService
  private verdaccioSecret: VerdaccioSecretService
  private downloads: DownloadsService
  private eventLog: EventLogService
  private gtadir: GlobalTadirService

  public constructor(config: StorageConfig, options: pluginUtils.PluginOptions) {
    debug('start storage plugin')

    if (ENV.DB_FALLBACK) {
      throw errorUtils.getServiceUnavailable('[sql-storage] Fallback to local storage plugin enabled')
    }

    super(config, options)
    this.config = options.config
    this.logger = options.logger

    this.storageConfig = { url: config?.url || ENV.DATABASE_URL }

    if (!this.storageConfig.url) {
      throw errorUtils.getServiceUnavailable(
        '[sql-storage] missing config. Add `url` to SQL Storage plugin config or use environment variable DATABASE_URL',
      )
    }

    this.db = getDatabase(this.storageConfig.url, this.logger)
    this.token = new TokenService(this.db, this.logger)
    this.localPackage = new LocalPackagesService(this.db, this.logger)
    this.verdaccioSecret = new VerdaccioSecretService(this.db, this.logger)
    this.downloads = new DownloadsService(this.db, this.logger)
    this.eventLog = new EventLogService(this.db, this.logger)
    this.gtadir = new GlobalTadirService(this.db, this.logger)

    debug('Verdaccio Pro SQL Storage plugin is enabled')
  }

  public async init(): Promise<void> {
    debug('init plugin')

    try {
      // Test database connection with a simple query
      await this.db.execute(sql`SELECT 1 as connection_test`)
      this.logger.info('database connection verified')
    }
    catch (error) {
      const errorMsg = error instanceof Error ? error.message : String(error)
      this.logger.error({ error: errorMsg }, 'database connection failed')

      // Provide helpful error messages based on common issues
      if (errorMsg.includes('ENOTFOUND') || errorMsg.includes('ECONNREFUSED')) {
        throw errorUtils.getServiceUnavailable(
          `[sql-storage] Cannot reach database server. Check DATABASE_URL is correct: ${this.storageConfig.url}`,
        )
      }
      else if (errorMsg.includes('self signed certificate') || errorMsg.includes('certificate')) {
        throw errorUtils.getServiceUnavailable(
          `[sql-storage] SSL certificate error. Try setting DB_SSL_REJECT_UNAUTHORIZED=false for self-signed certificates.`,
        )
      }
      else if (errorMsg.includes('password authentication failed')) {
        throw errorUtils.getServiceUnavailable(
          '[sql-storage] Database authentication failed. Check your credentials in DATABASE_URL.',
        )
      }
      else {
        throw errorUtils.getServiceUnavailable(
          `[sql-storage] Database connection failed: ${errorMsg}`,
        )
      }
    }

    try {
      // Check if migrations have been run by verifying the secrets table exists
      await this.db.execute(sql`SELECT to_regclass('public.secrets')`)
      const result = await this.db.execute<{ exists: boolean }>(
        sql`SELECT EXISTS (SELECT FROM information_schema.tables WHERE table_schema = 'public' AND table_name = 'secrets') as exists`,
      )

      const tableExists = result.rows[0]?.exists
      if (!tableExists) {
        throw new Error('Required database tables do not exist')
      }

      this.logger.info('database schema verified')
    }
    catch (error) {
      const errorMsg = error instanceof Error ? error.message : String(error)
      this.logger.error({ error: errorMsg }, 'database schema verification failed')

      throw errorUtils.getServiceUnavailable(
        `[sql-storage] Database tables are missing. Please run migrations first: nx db:migrate storage-sql`,
      )
    }

    debug('Verdaccio Pro SQL Storage plugin initialized')
  }

  // Storage API

  public getPackageStorage(packageName: string): SqlStorageHandler {
    return new SqlStorageHandler(this.db, this.logger, packageName)
  }

  // Secret API

  public async getSecret(): Promise<string> {
    debug('get secret')
    return this.verdaccioSecret.get()
  }

  public async setSecret(secret: string): Promise<string | null> {
    debug('set secret')
    return this.verdaccioSecret.set(secret)
  }

  // Package API

  public async get(): Promise<string[]> {
    debug('get complete package list')
    return this.localPackage.get()
  }

  public async add(packageName: string): Promise<void> {
    debug('add package %o', packageName)
    return this.localPackage.add(packageName)
  }

  public async remove(packageName: string): Promise<void> {
    debug('remove package %o', packageName)
    return this.localPackage.remove(packageName)
  }

  public async search(query: searchUtils.SearchQuery): Promise<searchUtils.SearchItem[]> {
    debug('search for %o', query.text)
    const results: searchUtils.SearchItem[] = []

    const localResults = await PackageService.search(this.db, query)
    debug('total results %o', localResults.length)

    const allPackages = await this.get()
    for (const result of localResults) {
      const isPrivate = allPackages.includes(result.name)
      // use time to store the ranking
      const score = {
        final: result.time as number,
        detail: {
          maintenance: 1,
          popularity: 1,
          quality: 1,
        },
      }
      results.push({
        package: result,
        verdaccioPrivate: isPrivate,
        verdaccioPkgCached: !isPrivate,
        score,
      })
    }

    return results
  }

  // eslint-disable-next-line @typescript-eslint/no-unused-vars
  private async getScore(item: searchUtils.SearchItemPkg): Promise<searchUtils.Score> {
    // TODO: there is no particular reason to predefined scores
    return {
      final: 1,
      detail: {
        maintenance: 0,
        popularity: 1,
        quality: 1,
      },
    }
  }

  // Token API

  public async readTokens(filter: TokenFilter): Promise<Token[]> {
    debug('get tokens for user %o', filter.user)
    return this.token.read(filter)
  }

  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  public async saveToken(token: Token): Promise<any> {
    debug('save token for user %o', token.user)
    return this.token.save(token)
  }

  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  public async deleteToken(user: string, tokenKey: string): Promise<any> {
    debug('delete token for user %o and token %o', user, tokenKey)
    return this.token.delete(user, tokenKey)
  }

  // Verdaccio Pro - Download Counters

  public async incrementDownloads(filename: string): Promise<void> {
    debug('increment downloads for tarball %o', filename)
    return this.downloads.increment(filename)
  }

  public async getDownloads(timeslice: string, start: string, end?: string): Promise<Downloads[] | null> {
    debug('get downloads from %o to %o for timeslice %o', start, end, timeslice)
    return this.downloads.getDownloads(timeslice, start, end)
  }

  public async getDownloadsByPackage(packageName: string, start: string, end?: string): Promise<Downloads[] | null> {
    debug('get downloads from %o to %o for package %o', start, end, packageName)
    return this.downloads.getByPackage(packageName, start, end)
  }

  public async getDownloadsByVersion(packageName: string, start: string, end?: string): Promise<DownloadsByVersion[] | null> {
    debug('get downloads from %o to %o for package %o', start, end, packageName)
    return this.downloads.getByVersion(packageName, start, end)
  }

  // Verdaccio Pro - Activity Log

  public async logActivity(user: string, method: Method, event: string, name: string, version?: string): Promise<void> {
    debug('activity %o', { user, method, event, name, version })
    return this.eventLog.log(user, method, event, name, version)
  }

  // Escape special characters (like lodash.escapeRegExp)
  private escapeRegExp(string: string): string {
    return string.replace(/[.*+?^${}()|[\]\\]/g, '\\$&')
  }
}

export default SqlStoragePlugin
